+    _ = ctx.eval(wrapped) catch |err| {
+        std.debug.print("Failed to eval module {s}: {}\n", .{ name, err });
+        if (ctx.getException()) |exc| {
+            defer exc.free();
+            if (exc.toStringSlice()) |msg| {
+                std.debug.print("Exception: {s}\n", .{msg});
+            }
+        }
+        return err;
+    };
